head.script:
scwin.sUserID       = "";
scwin.sUserName     = "";
scwin.strCurDate    = "";
scwin.sDate         = "";
scwin.strQryStDt    = "";
scwin.onSearchCode  = "INIT";

scwin.csVl3 = "";
scwin.csVl4 = "";
scwin.fl_masteridx = "";
scwin.fl_subidx = "";
scwin.fl_type = "";

scwin.onpageload = function() {

    scwin.sUserID      = $c.data.getMemInfo("userId");
    scwin.sUserName    = $c.data.getMemInfo("userClsCd"); 

    scwin.strCurDate   = $c.date.getServerDateTime("yyyyMMdd").substring(0, 8);			// 현재년월일을 구한다.
    scwin.sDate        = $c.date.getServerDateTime("yyyyMMdd");	                        // 현재일자를 구한다.
    scwin.strQryStDt   = scwin.sDate.substring(0, 6)+ "01";

};

scwin.onUdcCompleted = function () {
    $p.parent().wfm_wframe1.getWindow().scwin.reflashdata();
}
//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.udc_vehcl_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, txt_vehclShortCd.getValue(), txt_vehclNos.getValue(), 'F', 'F');
};


scwin.f_reflashdata = function() {
    let parentWin = $p.parent();
    if (parentWin && parentWin.scwin && typeof parentWin.scwin.reflashdata === "function") {
        parentWin.scwin.reflashdata();
    }
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
//    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
//TODO
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면

    switch (disGubun) {

        case 1:
            // 차량번호
            udc_vehcl.cfCommonPopUp(scwin.udc_vehcl_callback		// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch				// 전체검색허용여부	("F")
                                    ,"차량번호,차량단축코드,차량번호"					// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );
            break;

            default:
            break;
    }
};

scwin.udc_vehcl_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(txt_vehclShortCd, txt_vehclNos, 1, true);
};

scwin.udc_vehcl_onblurNameEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(txt_vehclNos, txt_vehclShortCd, 1, false);
};

scwin.udc_vehcl_callback = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, txt_vehclShortCd, txt_vehclNos);
};  


scwin.btn_searchCar_onclick = function (e) {
