scwin.showmbcar = async function(ton, dt) {

    dma_condition.setEmptyValue();
    dtl_car_mb.setData([]);
/*    상단화면 개발 완료후 처리
*/
//    $p.parent().wfm_wframe1.getWindow().selectedvehclRow.setValue("");
//    $p.parent().wfm_wframe1.getWindow().ez110Idx.setValue("");
//    $p.parent().wfm_wframe1.getWindow().vehclType.setValue("mb");

    $p.parent().wfm_wframe1.getWindow().scwin.selectedvehclRow = "";
    $p.parent().wfm_wframe1.getWindow().scwin.ez110Idx = "";
    $p.parent().wfm_wframe1.getWindow().scwin.vehclType = "mb";

    if (typeof ton === 'undefined' || ton == null ) {
        ton = "0";
    }
    if (typeof dt === 'undefined' || dt == null || dt == "") {
        dt = scwin.sDate;
    }
    dt = dt.replace("-", "");
    dt = dt.replace("-", "");

    dma_condition.set("ton", ton);
    dma_condition.set("dt", dt);

    dma_condition.set("vehclHdidx", $p.parent().wfm_wframe1.getWindow().ds_cond.getCellData(0,"vehclHdidx") );
    dma_condition.set("vehclBhidx", $p.parent().wfm_wframe1.getWindow().ds_cond.getCellData(0,"vehclBhidx") );
    dma_condition.set("vehclOfcidx", $p.parent().wfm_wframe1.getWindow().ds_cond.getCellData(0,"vehclOfcidx") );    

    $c.sbm.execute(sbm_search_car_mb);
};

scwin.showmbrequestcar = async function(fl_masteridx,fl_subidx,fl_type) {

    dma_condition.setEmptyValue();
    dtl_car_mb.setData([]);
/*    상단화면 개발 완료후 처리

*/
//    $p.parent().wfm_wframe1.getWindow().selectedvehclRow.setValue("");
//    $p.parent().wfm_wframe1.getWindow().ez110Idx.setValue("");
//    $p.parent().wfm_wframe1.getWindow().vehclType.setValue("mb");

    $p.parent().wfm_wframe1.getWindow().scwin.selectedvehclRow = "";
    $p.parent().wfm_wframe1.getWindow().scwin.ez110Idx = "";
    $p.parent().wfm_wframe1.getWindow().scwin.vehclType = "mb";

    scwin.fl_masteridx = fl_masteridx;
	scwin.fl_subidx = fl_subidx;
	scwin.fl_type   = fl_type;

    dma_condition.set("idx", fl_masteridx);

	if(fl_type == 'cont'){
        dma_condition.set("cntr", fl_subidx);
	}else if(fl_type=='cargo'){
        dma_condition.set("blk", fl_subidx);    
	}
	scwin.f_eventRadioClick(WebSquare.cookie.getCookie("csVl2"));

    dma_condition.set("dateOp", WebSquare.cookie.getCookie("csVl5"));
    dma_condition.set("dateCond1", scwin.csVl3);
    dma_condition.set("dateCond2", scwin.csVl4);

    $c.sbm.execute(sbm_search_car_matching);
};


scwin.f_eventRadioClick = function(No){

    var toDate = $c.date.getServerDateTime("yyyyMMdd");
	var toYear = toDate.toString().substring(0,4);
	var toMonth = toDate.toString().substring(4,6);
	var toDay = toDate.toString().substring(6,8);

	// Dt1 - 조회 시작일, Dt2 - 조회 종료일
	var toYearDt1, toYearDt2;
	var toMonthDt1, toMonthDt2;
	var toDayDt1, toDayDt2;
	var sDt1, sDt2;

	//toMonth 에 -1 을 안하면 +1 된 월값이 나온다.
	var NowDate = new Date(toYear,toMonth-1,toDay);

	switch(No){
			// 당일
			case '1':{
				// Object 에 날짜 입력(날짜는 20080101 형식)
				scwin.csVl3 = toDate;
				scwin.csVl4 = toDate;			 
				break;
			}
			// 금주
			case '2':{
				var numb = NowDate.getTime();
				var TempDay = NowDate.getDay();
				var TempDate = NowDate;
				/*
					조회 시작일
				*/
				TempDate.setTime(numb-(TempDay*1000*60*60*24));
				toYearDt1 = TempDate.getFullYear();
				toMonthDt1 = TempDate.getMonth() + 1; // +1 을 안하면 현재월보다 -1 된 값이 나온다.
				toDayDt1 = TempDate.getDate();				
				toMonthDt1 = '0' + toMonthDt1;
				toMonthDt1 = toMonthDt1.substr(toMonthDt1.length-2,toMonthDt1.length);				
				toDayDt1 = '0' + toDayDt1;
				toDayDt1 = toDayDt1.substr(toDayDt1.length-2,toDayDt1.length);				
				// 조회 시작일
				sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();

				/*
					조회 종료일
				*/
				TempDate.setTime(numb+((6 - TempDay)*1000*60*60*24));
				toYearDt2 = TempDate.getFullYear();
				toMonthDt2 = TempDate.getMonth() + 1; // +1 을 안하면 현재월보다 -1 된 값이 나온다.
				toDayDt2 = TempDate.getDate();				
				toMonthDt2 = '0' + toMonthDt2;
				toMonthDt2 = toMonthDt2.substr(toMonthDt2.length-2,toMonthDt2.length);				
				toDayDt2 = '0' + toDayDt2;
				toDayDt2 = toDayDt2.substr(toDayDt2.length-2,toDayDt2.length);
				// 조회 종료일				
				sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();

				// 조회일자 세팅  Object 에 날짜 입력(날짜는 20080101 형식)
				scwin.csVl3 = sDt1;
				scwin.csVl4 = sDt2;				
				break;
			}

			// 금월
			case '3':{
				var numb = NowDate.getTime();				
				var TempDate = NowDate;
				toMonthDt1 = NowDate.getMonth() + 1; // +1을 안하면 현재월보다 -1 된 값이 나온다.				
				toYearDt1 = TempDate.getFullYear();
				toMonthDt1 = '0' + toMonthDt1;
				toMonthDt1 = toMonthDt1.substr(toMonthDt1.length-2,toMonthDt1.length);
				toDayDt1 = '01';				
				// 조회 시작일
				sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();

				// M+1 월
				TempDate = new Date(toYearDt1, TempDate.getMonth()+1, toDayDt1);
				TempDate.setTime(TempDate.getTime() - (1*1000*60*60*24));

				toYearDt2 = TempDate.getFullYear();
				toMonthDt2 = TempDate.getMonth();
				toMonthDt2 = '0' + toMonthDt1;
				toMonthDt2 = toMonthDt2.substr(toMonthDt2.length-2,toMonthDt2.length);
				toDayDt2 = TempDate.getDate();				
				toDayDt2 = '0' + toDayDt2;
				toDayDt2 = toDayDt2.substr(toDayDt2.length-2,toDayDt2.length);						 
				// 조회 종료일				
				sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();

				// 조회일자 세팅  Object 에 날짜 입력(날짜는 20080101 형식)
				scwin.csVl3 = sDt1;
				scwin.csVl4 = sDt2;						
				break;
			}

			// 전월
			case '4':{
				var numb = NowDate.getTime();				
				var TempDate = NowDate;
				toMonthDt1 = NowDate.getMonth(); // +1을 안하면 현재월보다 -1 된 값이 나온다.				
				toYearDt1 = TempDate.getFullYear();
				toMonthDt1 = '0' + toMonthDt1;
				toMonthDt1 = toMonthDt1.substr(toMonthDt1.length-2,toMonthDt1.length);
				toDayDt1 = '01';				
				// 조회 시작일
				sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();

				// M+1 월
				TempDate = new Date(toYearDt1, TempDate.getMonth(), toDayDt1);
				TempDate.setTime(TempDate.getTime() - (1*1000*60*60*24));

				toYearDt2 = TempDate.getFullYear();
				toMonthDt2 = TempDate.getMonth();
				toMonthDt2 = '0' + toMonthDt1;
				toMonthDt2 = toMonthDt2.substr(toMonthDt2.length-2,toMonthDt2.length);
				toDayDt2 = TempDate.getDate();				
				toDayDt2 = '0' + toDayDt2;
				toDayDt2 = toDayDt2.substr(toDayDt2.length-2,toDayDt2.length);						 
				// 조회 종료일				
				sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();

				// 조회일자 세팅  Object 에 날짜 입력(날짜는 20080101 형식)
				scwin.csVl3 = sDt1;
				scwin.csVl4 = sDt2;				
				break;
			}

			// 지정
			case '5':{
				break;
			}
	}
}


