scwin.openmap = async function() {
    let condition = {};
    let activeTab = tac_car.getSelectedTabIndex();

    if (activeTab == 1) {
        let row = dtl_car_blk.getRowPosition();
        if (row < 0) return;
        condition.CARNO     = dtl_car_blk.getCellData(row, 'vehclNo');
        condition.CARSTS    = dtl_car_blk.getCellData(row, 'vehclSts');
        condition.USRNM     = dtl_car_blk.getCellData(row, 'picNm');
        condition.PHONENO   = dtl_car_blk.getCellData(row, 'handphoneNo');
        condition.POST      = dtl_car_blk.getCellData(row, 'posTxt');
        condition.TIME      = dtl_car_blk.getCellData(row, 'txnDate');
        condition.CARTYPE   = dtl_car_blk.getCellData(row, 'vehclNo');
        condition.XPOS      = dtl_car_blk.getCellData(row, 'xpos');
        condition.YPOS      = dtl_car_blk.getCellData(row, 'ypos');
    } else if (activeTab == 2) {
        let row = dtl_car_cntr.getRowPosition();
        if (row < 0) return;
        condition.CARNO     = dtl_car_cntr.getCellData(row, 'vehclNo');
        condition.CARSTS    = dtl_car_cntr.getCellData(row, 'vehclSts');
        condition.USRNM     = dtl_car_cntr.getCellData(row, 'picNm');
        condition.PHONENO   = dtl_car_cntr.getCellData(row, 'handphoneNo');
        condition.POST      = dtl_car_cntr.getCellData(row, 'posTxt');
        condition.TIME      = dtl_car_cntr.getCellData(row, 'txnDate');
        condition.CARTYPE   = dtl_car_cntr.getCellData(row, 'vehclNo');
        condition.XPOS      = dtl_car_cntr.getCellData(row, 'xpos');
        condition.YPOS      = dtl_car_cntr.getCellData(row, 'ypos');
    } else if (activeTab == 3) {
        let row = dtl_car_mb.getRowPosition();
        if (row < 0) return;
        condition.CARNO     = dtl_car_mb.getCellData(row, 'vehclNo');
        condition.CARSTS    = dtl_car_mb.getCellData(row, 'vehclSts');
        condition.USRNM     = dtl_car_mb.getCellData(row, 'picNm');
        condition.PHONENO   = dtl_car_mb.getCellData(row, 'handphoneNo');
        condition.POST      = dtl_car_mb.getCellData(row, 'posTxt');
        condition.TIME      = dtl_car_mb.getCellData(row, 'txnDate');
        condition.CARTYPE   = dtl_car_mb.getCellData(row, 'vehclNo');
        condition.XPOS      = dtl_car_mb.getCellData(row, 'xpos');
        condition.YPOS      = dtl_car_mb.getCellData(row, 'ypos');
    } else {
        let row = dtl_car.getRowPosition();
        if (row < 0) return;
        condition.CARNO     = dtl_car.getCellData(row, 'vehclNo');
        condition.CARSTS    = dtl_car.getCellData(row, 'vehclSts');
        condition.USRNM     = dtl_car.getCellData(row, 'picNm');
        condition.PHONENO   = dtl_car.getCellData(row, 'handphoneNo');
        condition.POST      = dtl_car.getCellData(row, 'posTxt');
        condition.TIME      = dtl_car.getCellData(row, 'txnDate');
        condition.CARTYPE   = dtl_car.getCellData(row, 'vehclNo');
        condition.XPOS      = dtl_car.getCellData(row, 'xpos');
        condition.YPOS      = dtl_car.getCellData(row, 'ypos');
    }

    await $c.win.openPopup("/ui/lbs/yb/yb/lbs_326_02_02p.xml", {
        width: 500,
        height: 660,
        modal: false},
         condition
    );
};


