scwin.f_runExcel = async function(varGrNm) {

//    var totCnt = ds_Present.getRowCount();
    var sheetTitle = "전체차량목록";
    var grw_name =  gr_car;
    let activeTab = tac_car.getSelectedTabIndex();

    if (activeTab == 1) {
        sheetTitle = "벌크차량목록";
        grw_name = gr_car_blk;
    }    
    if (activeTab == 2) {
        sheetTitle = "컨테이너차량목록";
        grw_name = gr_car_cntr;
    }    
    if (activeTab == 3) {
        sheetTitle = "최적차량목록";
        grw_name = gr_car_mb ;
    }            
/*
    if (!(totCnt > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
        return;
    }
*/
    let rtn = await $c.win.confirm( "Excel로 다운로드 하시겠습니까?" ); 

    if ( rtn ) {  // 리턴 처리

        const options = {
            fileName: sheetTitle+".xlsx",
            sheetName: sheetTitle
          , bodyWordwrap     : true   // 줄바꿈
        };

        $c.data.downloadGridViewExcel(grw_name, options);
    }
}

